// ─────────────────────────────────────────────────────────────────────────────
// routes/onboarding-token-routes.js
//
// Token-gated Med Spa onboarding flow.
// Tokens are generated by Stripe webhook after checkout.session.completed.
// Auto-regenerated on login if expired.
//
// GET  /api/onboarding/:token          — Validate token + return step progress
// POST /api/onboarding/:token/step     — Auto-save a step { step, data }
// POST /api/onboarding/:token/submit   — Submit onboarding → clinicStatus = onboarding_submitted
//
// No JWT auth required on these routes — the token IS the credential.
// ─────────────────────────────────────────────────────────────────────────────

import { prisma } from '../config/prisma.js';

// ─── Token validation helper ──────────────────────────────────────────────────
async function resolveToken(token, reply) {
  const record = await prisma.onboardingToken.findUnique({
    where:   { token },
    include: { tenant: { select: { id: true, name: true, clinicStatus: true, settings: true } } },
  });

  if (!record) {
    reply.code(404).send({ error: 'INVALID_TOKEN', message: 'Onboarding link not found.' });
    return null;
  }
  if (record.expiresAt < new Date()) {
    reply.code(410).send({ error: 'TOKEN_EXPIRED', message: 'This onboarding link has expired. Please log in to receive a new one.' });
    return null;
  }
  if (record.usedAt) {
    reply.code(409).send({ error: 'TOKEN_USED', message: 'This onboarding link has already been used. Your setup is complete.' });
    return null;
  }
  return record;
}

export default async function onboardingTokenRoutes(fastify) {

  // ── GET /api/onboarding/:token ─────────────────────────────────────────────
  // Validate token and return current step progress (for resuming wizard)
  fastify.get('/api/onboarding/:token', async (request, reply) => {
    const record = await resolveToken(request.params.token, reply);
    if (!record) return; // reply already sent

    const onboardingProgress = record.tenant.settings?.onboardingProgress ?? {};

    return {
      tenantId:    record.tenantId,
      tenantName:  record.tenant.name,
      clinicStatus: record.tenant.clinicStatus,
      currentStep: onboardingProgress.currentStep ?? 1,
      stepData:    onboardingProgress.stepData ?? {},
      expiresAt:   record.expiresAt,
    };
  });

  // ── POST /api/onboarding/:token/step ──────────────────────────────────────
  // Auto-save step data. Body: { step: 1-6, data: { ... } }
  fastify.post('/api/onboarding/:token/step', async (request, reply) => {
    const record = await resolveToken(request.params.token, reply);
    if (!record) return;

    const { step, data } = request.body ?? {};
    if (!step || !data) {
      return reply.code(400).send({ error: 'step and data are required' });
    }
    if (step < 1 || step > 6) {
      return reply.code(400).send({ error: 'step must be between 1 and 6' });
    }

    // Read current settings to merge (avoid overwriting other step data)
    const tenant = await prisma.tenant.findUnique({
      where:  { id: record.tenantId },
      select: { settings: true },
    });
    const settings           = tenant?.settings ?? {};
    const onboardingProgress = settings.onboardingProgress ?? { stepData: {} };

    onboardingProgress.stepData    = { ...onboardingProgress.stepData, [step]: data };
    onboardingProgress.currentStep = Math.max(onboardingProgress.currentStep ?? 1, step);
    settings.onboardingProgress    = onboardingProgress;

    await prisma.tenant.update({
      where: { id: record.tenantId },
      data:  { settings },
    });

    return { saved: true, step, currentStep: onboardingProgress.currentStep };
  });

  // ── POST /api/onboarding/:token/submit ────────────────────────────────────
  // Complete the onboarding wizard. Persists structured data and sets clinicStatus.
  fastify.post('/api/onboarding/:token/submit', async (request, reply) => {
    const record = await resolveToken(request.params.token, reply);
    if (!record) return;

    const { stepData } = request.body ?? {};
    if (!stepData) {
      return reply.code(400).send({ error: 'stepData is required' });
    }

    const tenantId = record.tenantId;

    await prisma.$transaction(async (tx) => {
      // Step 1 — Clinic Info → update Tenant settings
      if (stepData[1]) {
        const s1 = stepData[1];
        const existing = await tx.tenant.findUnique({
          where: { id: tenantId }, select: { settings: true },
        });
        await tx.tenant.update({
          where: { id: tenantId },
          data:  {
            name: s1.clinicName ?? record.tenant.name,
            settings: {
              ...(existing?.settings ?? {}),
              address:  s1.address,
              timezone: s1.timezone ?? 'America/New_York',
              phone:    s1.phone,
              website:  s1.website,
              instagram: s1.instagram,
            },
          },
        });
      }

      // Step 2 — Services → upsert Service records
      if (Array.isArray(stepData[2]?.services)) {
        for (const svc of stepData[2].services) {
          if (!svc.name) continue;
          await tx.service.create({
            data: {
              tenantId,
              name:                svc.name,
              durationMins:        parseInt(svc.durationMins, 10) || 60,
              priceCents:          Math.round((parseFloat(svc.avgPrice) || 0) * 100),
              consultationRequired: Boolean(svc.consultationRequired),
              category:            'Med Spa',
            },
          });
        }
      }

      // Step 3 — Consultation Rules → upsert ConsultationRule
      if (stepData[3]) {
        const s3 = stepData[3];
        await tx.consultationRule.upsert({
          where:  { tenantId },
          create: {
            tenantId,
            durationMins:  parseInt(s3.durationMins, 10) || 30,
            availableDays: s3.availableDays ?? [1, 2, 3, 4, 5],
            timeBlocks:    s3.timeBlocks ?? [{ start: '09:00', end: '17:00' }],
            bufferMins:    parseInt(s3.bufferMins, 10) || 15,
            maxPerDay:     parseInt(s3.maxPerDay, 10) || 10,
          },
          update: {
            durationMins:  parseInt(s3.durationMins, 10) || 30,
            availableDays: s3.availableDays ?? [1, 2, 3, 4, 5],
            timeBlocks:    s3.timeBlocks ?? [{ start: '09:00', end: '17:00' }],
            bufferMins:    parseInt(s3.bufferMins, 10) || 15,
            maxPerDay:     parseInt(s3.maxPerDay, 10) || 10,
          },
        });
      }

      // Step 4 — Call Handling → stored in Tenant.settings
      if (stepData[4]) {
        const s4 = stepData[4];
        const existing = await tx.tenant.findUnique({
          where: { id: tenantId }, select: { settings: true },
        });
        await tx.tenant.update({
          where: { id: tenantId },
          data:  {
            settings: {
              ...(existing?.settings ?? {}),
              callHandling: {
                transferNumber:   s4.transferNumber,
                afterHours:       s4.afterHoursHandling,
                emergencyKeywords: s4.emergencyKeywords ?? [],
                allowPriceQuoting: Boolean(s4.allowPriceQuoting),
              },
            },
          },
        });
      }

      // Step 5 — Brand Voice → upsert BrandVoice
      if (stepData[5]) {
        const s5 = stepData[5];
        await tx.brandVoice.upsert({
          where:  { tenantId },
          create: {
            tenantId,
            tone:             s5.tone ?? 'Friendly',
            wordsToAvoid:     s5.wordsToAvoid ?? [],
            specialMessaging: s5.specialMessaging ?? null,
          },
          update: {
            tone:             s5.tone ?? 'Friendly',
            wordsToAvoid:     s5.wordsToAvoid ?? [],
            specialMessaging: s5.specialMessaging ?? null,
          },
        });
      }

      // Step 6 — Operating Hours + Blackout Dates
      if (stepData[6]) {
        const s6 = stepData[6];
        const existing = await tx.tenant.findUnique({
          where: { id: tenantId }, select: { settings: true },
        });
        await tx.tenant.update({
          where: { id: tenantId },
          data:  {
            settings: {
              ...(existing?.settings ?? {}),
              businessHours: s6.weeklySchedule ?? {},
            },
          },
        });

        // Insert blackout dates (skip duplicates)
        if (Array.isArray(s6.blackoutDates)) {
          for (const entry of s6.blackoutDates) {
            const date = new Date(entry.date);
            if (isNaN(date.getTime())) continue;
            await tx.blackoutDate.upsert({
              where:  { tenantId_date: { tenantId, date } },
              create: { tenantId, date, reason: entry.reason ?? null },
              update: { reason: entry.reason ?? null },
            });
          }
        }
      }

      // Mark token as used and set clinicStatus = onboarding_submitted
      await tx.onboardingToken.update({
        where: { id: record.id },
        data:  { usedAt: new Date() },
      });

      await tx.tenant.update({
        where: { id: tenantId },
        data:  { clinicStatus: 'onboarding_submitted' },
      });

      // Log activity
      await tx.activityLog.create({
        data: {
          tenantId,
          type:        'onboarding_submitted',
          description: 'Clinic onboarding form submitted. Awaiting admin review.',
          icon:        '🏥',
          bgColor:     '#c9903a',
        },
      });
    });

    return reply.code(201).send({
      success:     true,
      clinicStatus: 'onboarding_submitted',
      message:     'Onboarding complete. Your clinic is being set up. We will notify you when access is ready.',
    });
  });
}
